// Testbench for ts2v-generated Nibble4Core
// Verifies: FETCH/DECODE/EXEC FSM, ALU ops, JMP/JZ, LD/ST, HLT
// Uses: cpu/build/nibble4_core.sv (generated from cpu/ts/nibble4_core.ts via ts2v)

`timescale 1ns / 1ps

module tb_nibble4_core;
    reg clk, rst_n, enable, bus_ack;
    reg  [3:0] bus_rdata;
    wire       bus_req;
    wire [7:0] bus_addr;
    wire [3:0] bus_wdata;
    wire       bus_wen;
    wire       halted;

    // Instantiate DUT (generated by ts2v from TypeScript)
    Nibble4Core dut (
        .clk(clk), .rst_n(rst_n), .enable(enable),
        .bus_rdata(bus_rdata), .bus_ack(bus_ack),
        .bus_req(bus_req), .bus_addr(bus_addr),
        .bus_wdata(bus_wdata), .bus_wen(bus_wen),
        .halted(halted)
    );

    // 27MHz clock (Tang Nano 9K)
    initial clk = 0;
    always #18.5 clk = ~clk;

    // Simple memory model: 256 nibbles
    reg [3:0] memory [0:255];
    integer pass_count = 0;
    integer fail_count = 0;

    task check(input [127:0] name, input expected, input actual);
        if (expected === actual) begin
            $display("  PASS: %0s (expected=%0d, got=%0d)", name, expected, actual);
            pass_count = pass_count + 1;
        end else begin
            $display("  FAIL: %0s (expected=%0d, got=%0d)", name, expected, actual);
            fail_count = fail_count + 1;
        end
    endtask

    // Bus responder: single-cycle memory access
    always @(posedge clk) begin
        bus_ack <= 0;
        if (bus_req && !bus_ack) begin
            if (bus_wen) begin
                memory[bus_addr] <= bus_wdata;
            end else begin
                bus_rdata <= memory[bus_addr];
            end
            bus_ack <= 1;
        end
    end

    // Load a program into memory
    // Each instruction is 2 nibbles (opcode, operand)
    // LDI with immediate takes 3 nibbles
    task load_program_ldi_add_hlt;
        // LDI R0, 3   (opcode=1, reg=0, imm=3) -> nibbles: 1, 0, 3
        memory[0] = 4'h1;  // LDI opcode
        memory[1] = 4'h0;  // register R0
        memory[2] = 4'h3;  // immediate = 3

        // LDI R1, 5   -> nibbles: 1, 1, 5
        memory[3] = 4'h1;  // LDI
        memory[4] = 4'h1;  // R1
        memory[5] = 4'h5;  // immediate = 5

        // ADD (R0 = R0 + R1 = 3+5 = 8)
        memory[6] = 4'h4;  // ADD
        memory[7] = 4'h0;  // unused

        // HLT
        memory[8] = 4'hF;  // HLT
        memory[9] = 4'h0;
    endtask

    task load_program_jz;
        // LDI R0, 0
        memory[0] = 4'h1; memory[1] = 4'h0; memory[2] = 4'h0;
        // JZ to addr 9 (should jump because R0=0, Z=1)
        memory[3] = 4'hD; memory[4] = 4'h0; memory[5] = 4'h9;
        // This should be skipped:
        memory[6] = 4'h1; memory[7] = 4'h0; memory[8] = 4'hF;
        // HLT at addr 9
        memory[9] = 4'hF; memory[10] = 4'h0;
    endtask

    task load_program_logic;
        // LDI R0, 0xA (1010)
        memory[0] = 4'h1; memory[1] = 4'h0; memory[2] = 4'hA;
        // LDI R1, 0x5 (0101)
        memory[3] = 4'h1; memory[4] = 4'h1; memory[5] = 4'h5;
        // AND: R0 = 0xA & 0x5 = 0x0
        memory[6] = 4'h6; memory[7] = 4'h0;
        // HLT
        memory[8] = 4'hF; memory[9] = 4'h0;
    endtask

    // Run a program and wait for halt
    task run_until_halt(input integer max_cycles);
        integer i;
        begin
            enable = 1;
            for (i = 0; i < max_cycles; i = i + 1) begin
                @(posedge clk);
                if (halted) begin
                    $display("  Halted after %0d cycles", i);
                    disable run_until_halt;
                end
            end
            $display("  TIMEOUT after %0d cycles", max_cycles);
        end
    endtask

    initial begin
        $dumpfile("tb_nibble4_core.vcd");
        $dumpvars(0, tb_nibble4_core);

        // Reset
        rst_n = 0; enable = 0; bus_ack = 0; bus_rdata = 0;
        #100;
        rst_n = 1;
        #50;

        // ===== TEST 1: LDI + ADD + HLT =====
        $display("\n=== TEST 1: LDI + ADD + HLT ===");
        rst_n = 0; #50; rst_n = 1; #20;
        load_program_ldi_add_hlt;
        run_until_halt(500);
        check("halted", 1, halted);
        check("R0 = 3+5 = 8", 4'h8, dut.r0);
        check("R1 = 5", 4'h5, dut.r1);
        check("PC advanced", 1, dut.pc > 8);

        // ===== TEST 2: JZ (conditional jump) =====
        $display("\n=== TEST 2: JZ ===");
        rst_n = 0; #50; rst_n = 1; #20;
        load_program_jz;
        run_until_halt(500);
        check("halted", 1, halted);
        // If JZ worked, R0 should still be 0 (the 0xF load was skipped)
        check("R0 after JZ = 0", 4'h0, dut.r0);

        // ===== TEST 3: Logic (AND) =====
        $display("\n=== TEST 3: AND ===");
        rst_n = 0; #50; rst_n = 1; #20;
        load_program_logic;
        run_until_halt(500);
        check("halted", 1, halted);
        check("R0 = 0xA & 0x5 = 0", 4'h0, dut.r0);
        check("Z flag set", 1, dut.flag_z);

        // ===== SUMMARY =====
        $display("\n=================================");
        $display("Tests: %0d passed, %0d failed", pass_count, fail_count);
        $display("=================================");
        if (fail_count > 0) $display("SOME TESTS FAILED");
        else $display("ALL TESTS PASSED");
        $finish;
    end
endmodule
